  val visited = Array.ofDim[Boolean](rows, cols)
  val q = Queue[(Int, Int)]()

  for (i <- 0 until rows) {
    for (j <- 0 until cols) {
      if (grid(i)(j)) {
        q enqueue (i, j)
      }
    }
  }

  var count = 0
  while (q.nonEmpty) {
    val (r, c) = q dequeue
    if (visited(r)(c)) continue
    visited(r)(c) = true
    count += 1

