import scala.collection.mutable

def solve(n: Long, m: Long, k: Long): Long = {
  if (k == 0) return n * m
  if (n == 1 && m == 1) return 1
  if (k >= math.max(n, m) / 2) return 1

  val grid = mutable.ArrayBuffer.fill(n.toInt)(mutable.ArrayBuffer.fill(m.toInt)(0))
  val visited = mutable.ArrayBuffer.fill(n.toInt)(mutable.ArrayBuffer.fill(m.toInt)(false))
  var count = 0

  def canCover(r: Int, c: Int): Boolean = {
    for (i <- 0 until n) {
      for (j <- 0 until m) {
        if (math.max(math.abs(i - r), math.abs(j - c)) > k) return false
      }
    }
    true
  }

  def dfs(r: Int, c: Int): Unit = {
    if (r < 0 || r >= n || c < 0 || c >= m || visited(r)(c)) return
    visited(r)(c) = true
    for (i <- 0 until n) {
      for (j <- 0 until m) {
        if (math.max(math.abs(i - r), math.abs(j - c)) <= k && !visited(i)(j)) {
          dfs(i, j)
        }
      }
    }
  }

  for (i <- 0 until n) {
    for (j <- 0 until m) {
      if (!visited(i)(j)) {
        count += 1
        dfs(i, j)
      }
    }
  }

  count
}
